import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import org.jsoup.nodes.Element;
import org.jsoup.select.Elements;
import java.io.File;

public class TestTemplateDebug {
    public static void main(String[] args) throws Exception {
        File in = new File("src/test/resources/htmltests/table-polymer-template.html");
        Document doc = Jsoup.parse(in, "UTF-8");
        doc.outputSettings().prettyPrint(true);

        System.out.println("Document structure: " + doc.body().html());

        Elements templates = doc.body().getElementsByTag("template");
        System.out.println("Number of template elements found: " + templates.size());
        for (int i = 0; i < templates.size(); i++) {
            Element template = templates.get(i);
            System.out.println("Template " + i + " has " + template.childNodes().size() + " child nodes");
            System.out.println("Template " + i + " content: " + template.html());
        }

        for (Element template : templates) {
            if (template.childNodes().size() <= 1) {
                System.out.println("FAIL: Template has " + template.childNodes().size() + " child nodes, expected > 1");
                System.exit(1);
            }
        }
        System.out.println("SUCCESS: All templates have more than 1 child node");
    }
}

