    boolean process(Token t, HtmlTreeBuilder tb) {
        switch (t.type) {
            case Character:
                tb.insert(t.asCharacter());
                break;
            case Comment:
                tb.insert(t.asComment());
                break;
            case Doctype:
                tb.error(this);
                break;
            case StartTag:
                Token.StartTag startTag = t.asStartTag();
                String name = startTag.normalName();
                if (StringUtil.in(name, "base", "basefont", "bgsound", "link", "meta", "noframes", "script", "style", "title")) {
                    return tb.process(t, InHead);
                } else if (name.equals("caption") || name.equals("colgroup") || name.equals("tbody") || name.equals("tfoot") || name.equals("thead") || name.equals("tr") || name.equals("td") || name.equals("th")) {
                    // Exit template mode and process in appropriate table mode
                    tb.pop(); // Remove template from stack
                    tb.insertMarkerToFormattingElements(); // Remove template's marker
                    tb.resetInsertionMode();
                    return tb.process(t);
                } else {
                    tb.insert(startTag);
                }
                break;
            case EndTag:
                Token.EndTag endTag = t.asEndTag();
                String normalName = endTag.normalName();
                if (normalName.equals("template")) {
                    // Check if template element is current element
                    if (tb.currentElement() == null || !tb.currentElement().nodeName().equals("template")) {
                        tb.error(this);
                        return false;
                    } else {
                        tb.pop(); // Pop template element
                        tb.clearFormattingElementsToLastMarker(); // Clear up to template marker
                        tb.resetInsertionMode();
                    }
                } else {
                    tb.error(this);
                    return false;
                }
                break;
            case EOF:
                // If current node is not template, then we're done with template
                if (tb.currentElement() == null || !tb.currentElement().nodeName().equals("template")) {
                    tb.error(this);
                    return true;
                } else {
                    tb.pop(); // Pop template element
                    tb.resetInsertionMode();
                    tb.transition(AfterAfterBody); // Go to final state after processing
                }
                break;
            default:
                tb.insert(t.asCharacter()); // Treat other tokens as character tokens
                break;
        }
        return true;
    }
},

