import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import org.jsoup.nodes.Element;
import org.jsoup.select.Elements;

public class SimpleTemplateTest {
    public static void main(String[] args) throws Exception {
        String html = "<table style=\"width:100%\">\n" +
                "  <thead>\n" +
                "    <th></th>\n" +
                "    <template is=\"dom-repeat\" items=\"{{fields_}}\" as=\"field\">\n" +
                "      <th class$=\"[[cssClassForCell_(field.key, showAll_)]]\">{{field.name}}</th>\n" +
                "    </template>\n" +
                "  </thead>\n" +
                "  <tbody>\n" +
                "    <tr></tr>\n" +
                "    <template is=\"dom-repeat\" items=\"{{volumes_}}\" as=\"volume\">\n" +
                "      <tr class$=\"[[cssClassForVolume_(volume.inactive, showInactive_)]]\">\n" +
                "        <td style=\"background-color: white !important;\">\n" +
                "          <paper-button on-tap=\"onRetrieveButtonClick_\" raised>Retrieve</paper-button>\n" +
                "        </td>\n" +
                "        <template is=\"dom-repeat\" items=\"{{volume.data}}\" as=\"field\">\n" +
                "          <td class$=\"[[cssClassForCell_(field.key, showAll_)]]\">\n" +
                "            {{field.value}}\n" +
                "            <template is=\"dom-if\" if=\"{{field.edit_link}}\">\n" +
                "              <iron-icon\n" +
                "                icon=\"icons:create\" on-click=\"changeOwner_\"\n" +
                "                data-id$=\"{{volume.id}}\" data-owner$=\"{{field.value}}\">\n" +
                "              </iron-icon>\n" +
                "            </template>\n" +
                "          </td>\n" +
                "        </template>\n" +
                "      </tr>\n" +
                "    </template>\n" +
                "  </tbody>\n" +
                "</table>";

        Document doc = Jsoup.parse(html);
        System.out.println("HTML structure:\n" + doc.html());

        Elements templates = doc.getElementsByTag("template");
        System.out.println("Found " + templates.size() + " template elements:");

        for (int i = 0; i < templates.size(); i++) {
            Element template = templates.get(i);
            System.out.println("Template " + i + ": has " + template.childNodes().size() + " child nodes");
            System.out.println("Template " + i + " content: " + template.html());
        }
    }
}

